import{_ as t,o as s,c as i,ae as a}from"./chunks/framework.DeBUZsJm.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/overview.md","filePath":"zh/catter/overview.md"}'),o={name:"zh/catter/overview.md"};function n(l,e,c,r,d,h){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Catter probably can be divided into 3 parts:</p><ol><li><strong>HOOK</strong>: Intercept compilation commands from any build system.</li><li><strong>PROXY</strong>: Act as a proxy compiler to capture commands.</li><li><strong>DECISION</strong>: Communicate with the PROXY to determine how to handle commands.</li></ol><p>General process follows like this:</p><ol><li>User runs <code>catter &lt;build command&gt;</code>.</li><li><code>catter</code> starts the Decision-making Server and delegates execution by spawning <code>&lt;catter-proxy&gt; &lt;build command&gt;</code>.</li><li><strong>PROXY</strong> starts. It queries <strong>DECISION</strong>, which instructs it to execute the build command with <strong>HOOK</strong> attached (e.g., via <code>LD_PRELOAD</code> or DLL Injection etc.).</li><li>The build system runs. When it attempts to spawn a compiler (e.g., <code>g++ ...</code>), the <strong>HOOK</strong> intercepts the call.</li><li><strong>HOOK</strong> rewrites the execution call to redirect to <code>&lt;catter-proxy&gt; &lt;compiler command&gt;</code>.</li><li><strong>PROXY</strong> starts. It sends the captured arguments to <strong>DECISION</strong>.</li><li><strong>DECISION</strong> analyzes the arguments (using the user&#39;s JS script) and replies with an action (e.g., &quot;Execute&quot;, &quot;Hook and Execute&quot;, &quot;Skip&quot;, etc).</li><li><strong>PROXY</strong> performs the action requested by <strong>DECISION</strong>.</li></ol><hr><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><ol><li><code>catter</code> acts as <strong>DECISION</strong>: The user entry point. It runs as a daemon/server that holds the JS runtime. It instructs the PROXY on what to do but never interacts with the OS processes directly.</li><li><code>catter-proxy</code> acts as <strong>PROXY</strong>: The platform-specific tool, which private to users. It handles process creation, hook injection, and IPC communication. It acts in two modes: <ul><li><strong>Injector Mode:</strong> Launches the build system (e.g., <code>make</code>) with hooks attached.</li><li><strong>Wrapper Mode:</strong> Masquerades as the compiler (e.g., <code>g++</code>) to capture arguments.</li></ul></li></ol><blockquote><p><code>catter-proxy</code> includes processing logic of <strong>HOOK</strong>, which has different implementations on different platforms and we can&#39;t give a specific name here. For example, on Windows, it uses DLL injection with a specific DLL name like <code>catter-hook.dll</code>.</p></blockquote><p>We use <code>--</code> to separate commands for <code>catter</code> and commands for the actual build system. For example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build system command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter-proxy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compiler command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><ul><li>The first parameter of <code>catter</code> is always used to specify the script.</li><li>Then, you can provide specific options for scripts.</li><li>Finally, after <code>--</code>, you provide the actual build system command that you want to run.</li></ul><p>To specify a built-in script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">script-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build system command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>or custom script path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/custom/script.js</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build system command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><hr><h2 id="a-simple-example" tabindex="-1">A Simple Example <a class="header-anchor" href="#a-simple-example" aria-label="Permalink to &quot;A Simple Example&quot;">​</a></h2><ol><li>User runs:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/compile_commands.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div></li><li><code>catter</code> starts the Decision-making Server and spawns:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> catter-proxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div></li><li><code>catter-proxy</code> (PID: 100) starts. <ul><li>Connects to <code>catter</code> Server.</li><li><code>catter</code> instructs: This is a build command, execute it with hooks.</li><li><code>catter-proxy</code> injects hooks and starts <code>make</code> (PID: 101).</li></ul></li><li><code>make</code> (PID: 101) runs with hooks. It parses the Makefile and prepares to execute <code>g++</code>.</li><li><strong>HOOK</strong> (inside <code>make</code>): Intercepts the spawn call for <code>g++</code>. It rewrites the arguments to <code>catter-proxy -- g++</code> and spawns a new process.</li><li><code>catter-proxy</code> (PID: 102) starts. <ul><li>Connects to <code>catter</code> Server.</li><li><code>catter</code> instructs: This is a compile command, record it in the database and then execute the original command.</li><li><code>catter-proxy</code> executes <code>g++</code> (PID: 103).</li></ul></li><li><code>g++</code> (PID: 103) compiles normally.</li><li><code>catter</code> collects all compilation commands in its database and can export them as a <code>compile_commands.json</code> file when <code>make</code> finishes.</li></ol>`,19)])])}const g=t(o,[["render",n]]);export{k as __pageData,g as default};
